module.exports = /*#__PURE__*/JSON.parse('{"page_title":"X Save: Trình tải xuống video Twitter HD | Trình chuyển đổi X sang MP4","download":"Tải xuống","faq":"Câu hỏi thường gặp","about":"Giới thiệu","home":"Trang chủ","more":"Thêm","all_rights_reserved":"Tất cả các quyền được bảo lưu.","oops":"Ôi!","privacy_policy":"Chính sách bảo mật","disclaimer_page_title":"Tuyên bố miễn trừ trách nhiệm","contact_us":"Liên hệ chúng tôi","footer_disclaimer_short":"XSave không lưu trữ bất kỳ video, hình ảnh hoặc GIF nào. Tất cả nội dung thuộc về chủ sở hữu tương ứng của họ. Chúng tôi không liên kết với Twitter/X.","footer_site_description":"Tải xuống video và GIF Twitter/X ngay lập tức — nhanh chóng, miễn phí và an toàn.","footer_nav_product":"Sản phẩm","footer_nav_company":"Công ty","footer_nav_legal":"Pháp lý","twitter_video_downloader":"Trình tải xuống video X Twitter","paste_url_prompt":"Dán URL của bất kỳ video hoặc GIF Twitter/X nào bên dưới để tạo liên kết tải xuống tức thì.","enter_url_placeholder":"https://x.com/username/status/...","error_enter_url":"Vui lòng nhập URL Twitter/X.","error_invalid_url":"URL Twitter/X được cung cấp không hợp lệ. Vui lòng kiểm tra liên kết và thử lại.","error_private_video":"Video này là riêng tư, đã bị xóa hoặc từ một tài khoản bạn không có quyền truy cập.","error_bad_response":"Không thể lấy dữ liệu video. Tweet có thể không chứa video hoặc đã xảy ra lỗi máy chủ.","error_generic":"Đã xảy ra lỗi không xác định. Vui lòng kiểm tra kết nối của bạn và thử lại.","xsave_title":"X Save: Trình tải xuống video Twitter","xsave_description_1":"XSave.app là một công cụ tải xuống video Twitter; nó nhanh, an toàn và đáng tin cậy. Sử dụng công cụ của chúng tôi, bạn có thể lưu một meme lan truyền, một bản tin cập nhật hoặc bất kỳ video, GIF nào, v.v. Điều tuyệt vời nhất về XSave là bạn không cần đăng ký để sử dụng nó; chỉ cần dán liên kết và tải xuống video Twitter ở chế độ HD.","xsave_description_2":"Công cụ của chúng tôi được xây dựng với trải nghiệm người dùng là trọng tâm; không cần cài đặt bất kỳ tiện ích mở rộng trình duyệt hoặc phần mềm nào. Khi bạn dán URL của bất kỳ video Twitter/X nào, hệ thống phụ trợ mạnh mẽ của chúng tôi sẽ tìm nạp tất cả các chất lượng video có sẵn để bạn tải xuống chỉ bằng một cú nhấp chuột.","how_to_title":"Làm cách nào để tải xuống video Twitter/X bằng XSave?","how_to_use_nav":"Cách sử dụng","how_to_step_1":"Đầu tiên, hãy truy cập Twitter/X và tìm video/GIF bạn muốn tải xuống.","how_to_step_2":"Bây giờ, hãy nhấp vào nút chia sẻ và sao chép URL video.","how_to_step_3":"Mở bất kỳ trình duyệt web nào trên thiết bị của bạn, nhập xsave.app vào thanh địa chỉ và nhấn Enter để truy cập trang web.","how_to_step_4":"Dán liên kết Video Twitter vào XSave và nhấn nút tải xuống để tìm nạp tất cả các chất lượng video có sẵn.","how_to_step_5":"Nhấn vào chất lượng video ưa thích của bạn để bắt đầu tải xuống.","features_title":"Các tính năng của Trình tải xuống video X","feature_1":"🚀 <strong>Nhanh chóng và Dễ dàng</strong> – Dán liên kết tweet và nhấn tải xuống, và trong vòng vài giây, video sẽ được tải xuống.","feature_2":"🎥 <strong>Chất lượng HD</strong> – Hệ thống của chúng tôi tìm nạp tất cả các độ phân giải có sẵn; bạn có thể chọn từ HD đến nhiều loại khác.","feature_3":"🔒 <strong>An toàn và Riêng tư</strong> – XSave.app không yêu cầu đăng nhập hoặc các thủ thuật ẩn và không có phần mềm độc hại.","feature_4":"🌐 <strong>Hoạt động ở mọi nơi</strong> – Bạn có thể sử dụng công cụ của chúng tôi trên bất kỳ nền tảng nào có truy cập internet, cho dù đó là máy tính để bàn, máy tính bảng hay thiết bị di động.","faq_title":"Các câu hỏi thường gặp","faq_q1":"Làm cách nào để sử dụng Trình tải xuống video Twitter/X?","faq_a1":"Sao chép URL tweet có chứa video hoặc GIF, dán vào hộp trên XSave.app và nhấn nút tải xuống.","faq_q2":"Dịch vụ này có miễn phí sử dụng không?","faq_a2":"Có, X Save hoàn toàn miễn phí. Không có phí ẩn hoặc phí đăng ký. Bạn có thể tải xuống bao nhiêu video tùy thích.","faq_q3":"Tôi có thể tải xuống video từ các tài khoản riêng tư không?","faq_a3":"Không, Xsave.app chỉ truy cập nội dung công khai; chúng tôi tôn trọng quyền riêng tư của người dùng và không bỏ qua cài đặt quyền riêng tư của X.","faq_q4":"Tôi có thể tải xuống video chất lượng nào?","faq_a4":"Chất lượng video phụ thuộc vào video gốc được tải lên Twitter/X. Công cụ của chúng tôi sẽ tìm nạp tất cả các chất lượng có sẵn như SD và HD, và bạn có thể chọn theo nhu cầu của mình.","faq_q5":"Tải xuống video Twitter có hợp pháp không?","faq_a5":"Tải xuống video nói chung chỉ dành cho mục đích sử dụng cá nhân của bạn. Vui lòng không sử dụng lại video mà không có sự cho phép của chủ sở hữu. Ngoài ra, hãy đảm bảo bạn biết luật bản quyền của quốc gia mình.","faq_q6":"Tại sao nên sử dụng XSave.app để chuyển đổi Twitter sang MP4?","faq_a6":"XSave là công cụ tải xuống video Twitter/X tốt nhất vì nó nhanh, miễn phí, an toàn và không yêu cầu bạn đăng ký.","about_title":"Giới thiệu về XSave","about_p1":"XSave được tạo ra vì một lý do đơn giản: đôi khi bạn tìm thấy một video hoặc GIF trên Twitter/X mà bạn không muốn mất. Có thể đó là một meme hài hước, một đoạn tin tức hoặc một thứ gì đó bạn muốn chia sẻ sau này. Với XSave, bạn có thể giữ nó chỉ bằng vài cú nhấp chuột.","about_p2":"Chúng tôi đã giữ nó đơn giản—không cần đăng ký, không có cửa sổ bật lên hoặc phần mềm để cài đặt. Sao chép liên kết tweet, dán vào trang web của chúng tôi và tải xuống video với chất lượng bạn thích.","about_p3":"Phía sau hậu trường, XSave sử dụng các công cụ mã nguồn mở đáng tin cậy để lấy video trực tiếp từ Twitter/X. Chúng tôi không lưu tệp của bạn, chúng tôi không ghi lại những gì bạn tải xuống và chúng tôi không lưu trữ bất kỳ phương tiện nào trên máy chủ của mình.","about_why_title":"Tại sao nên sử dụng XSave?","about_why_feature_1":"<strong>Miễn phí mãi mãi.</strong> Không có phí ẩn hoặc giới hạn.","about_why_feature_2":"<strong>Nhanh chóng và đơn giản.</strong> Sao chép, dán, tải xuống.","about_why_feature_3":"<strong>Hoạt động ở mọi nơi.</strong> Di động, máy tính bảng hoặc máy tính để bàn.","about_note_title":"Lưu ý","about_note_p1":"XSave không được kết nối với Twitter hoặc X Corp. Mọi quyền đều thuộc về những người sáng tạo ban đầu. Vui lòng sử dụng công cụ một cách có trách nhiệm và tuân thủ luật bản quyền.","privacy_title":"Chính sách bảo mật cho XSave","privacy_intro":"Tại XSave, có thể truy cập từ xsave.app, một trong những ưu tiên hàng đầu của chúng tôi là quyền riêng tư của khách truy cập. Tài liệu Chính sách bảo mật này chứa các loại thông tin được XSave thu thập và ghi lại cũng như cách chúng tôi sử dụng nó.","privacy_info_we_collect_title":"Thông tin chúng tôi thu thập","privacy_info_we_collect_p1":"Chúng tôi không yêu cầu người dùng đăng ký tài khoản hoặc cung cấp bất kỳ thông tin cá nhân nào để sử dụng dịch vụ của chúng tôi. Thông tin duy nhất chúng tôi xử lý là URL Twitter/X mà bạn gửi trong trường nhập liệu. Chúng tôi không lưu trữ các URL này sau khi yêu cầu được xử lý.","privacy_log_files_title":"Tệp nhật ký","privacy_log_files_p1":"XSave tuân theo một quy trình tiêu chuẩn về việc sử dụng tệp nhật ký. Các tệp này ghi lại khách truy cập khi họ truy cập các trang web. Thông tin được thu thập bởi các tệp nhật ký bao gồm địa chỉ giao thức internet (IP), loại trình duyệt, dấu ngày và giờ và các trang giới thiệu/thoát. Những thông tin này không được liên kết với bất kỳ thông tin nào có thể nhận dạng cá nhân. Mục đích của thông tin là để phân tích xu hướng, quản trị trang web và thu thập thông tin nhân khẩu học để sử dụng nội bộ nhằm cải thiện dịch vụ của chúng tôi.","privacy_cookies_title":"Cookie và Web Beacon","privacy_cookies_p1":"Giống như bất kỳ trang web nào khác, XSave sử dụng \\"cookie\\". Các cookie này được sử dụng để lưu trữ thông tin bao gồm cả sở thích của khách truy cập, chẳng hạn như cài đặt ngôn ngữ và chủ đề. Thông tin này được sử dụng để tối ưu hóa trải nghiệm của người dùng bằng cách tùy chỉnh nội dung trang web của chúng tôi dựa trên loại trình duyệt của khách truy cập và/hoặc thông tin khác.","privacy_third_party_title":"Dịch vụ của bên thứ ba","privacy_third_party_p1":"Chúng tôi không sử dụng bất kỳ dịch vụ nào của bên thứ ba có thể thu thập dữ liệu cá nhân từ người dùng của chúng tôi. Chúng tôi có thể sử dụng các dịch vụ phân tích tổng hợp dữ liệu sử dụng ẩn danh.","privacy_your_rights_title":"Quyền bảo vệ dữ liệu của bạn","privacy_your_rights_p1":"Vì chúng tôi không thu thập thông tin cá nhân, nhiều quyền bảo vệ dữ liệu tiêu chuẩn có thể không áp dụng trong bối cảnh thông thường. Tuy nhiên, chúng tôi cam kết bảo vệ quyền riêng tư của người dùng. Nếu bạn có bất kỳ câu hỏi hoặc thắc mắc nào về quyền riêng tư của mình khi sử dụng dịch vụ của chúng tôi, vui lòng liên hệ với chúng tôi.","privacy_consent_title":"Sự đồng ý","privacy_consent_p1":"Bằng cách sử dụng trang web của chúng tôi, bạn đồng ý với Chính sách bảo mật của chúng tôi và đồng ý với các điều khoản của nó.","disclaimer_intro":"Thông tin được cung cấp bởi XSave trên xsave.app chỉ dành cho mục đích thông tin chung và sử dụng cá nhân. Tất cả thông tin trên Trang web được cung cấp một cách thiện chí, tuy nhiên chúng tôi không tuyên bố hoặc bảo đảm bất kỳ loại nào, dù rõ ràng hay ngụ ý, về tính chính xác, đầy đủ, hợp lệ, độ tin cậy, tính sẵn có hoặc tính đầy đủ của bất kỳ thông tin nào trên Trang web.","disclaimer_accuracy_title":"Độ chính xác của nội dung","disclaimer_accuracy_p1":"Mặc dù chúng tôi cố gắng cung cấp một dịch vụ đáng tin cậy, chúng tôi không đảm bảo tính chính xác hoặc tính sẵn có của các liên kết tải xuống video. Chức năng của dịch vụ phụ thuộc vào khả năng truy cập liên tục của nội dung Twitter/X.","disclaimer_external_links_title":"Tuyên bố miễn trừ trách nhiệm về liên kết bên ngoài","disclaimer_external_links_p1":"Trang web có thể chứa các liên kết đến các trang web hoặc nội dung khác thuộc sở hữu hoặc có nguồn gốc từ bên thứ ba. Các liên kết bên ngoài như vậy không được chúng tôi điều tra, giám sát hoặc kiểm tra về tính chính xác, đầy đủ, hợp lệ, độ tin cậy, tính sẵn có hoặc tính đầy đủ.","disclaimer_personal_responsibility_title":"Trách nhiệm cá nhân","disclaimer_personal_responsibility_p1":"Bạn hoàn toàn chịu trách nhiệm về bất kỳ nội dung nào bạn tải xuống thông qua dịch vụ của chúng tôi. Bạn có trách nhiệm đảm bảo rằng bạn không vi phạm bất kỳ luật bản quyền nào hoặc các điều khoản dịch vụ của Twitter/X. XSave không chịu trách nhiệm về bất kỳ việc lạm dụng dịch vụ này.","disclaimer_no_affiliation_title":"Không có liên kết","disclaimer_no_affiliation_p1":"XSave là một dự án độc lập và không được liên kết, liên kết, ủy quyền, xác nhận bởi hoặc theo bất kỳ cách nào chính thức kết nối với X Corp (trước đây là Twitter, Inc.), hoặc bất kỳ công ty con hoặc chi nhánh nào của nó.","contact_title":"Liên hệ chúng tôi","contact_intro":"Có câu hỏi, đề xuất hoặc phản hồi? Chúng tôi rất muốn nghe từ bạn! Vui lòng điền vào biểu mẫu bên dưới và chúng tôi sẽ liên hệ lại với bạn sớm nhất có thể.","contact_form_name_label":"Tên của bạn","contact_form_name_placeholder":"Nhập tên của bạn","contact_form_email_label":"Email của bạn","contact_form_email_placeholder":"Nhập địa chỉ email của bạn","contact_form_message_label":"Tin nhắn của bạn","contact_form_message_placeholder":"Nhập tin nhắn của bạn ở đây...","contact_form_submit_button":"Gửi tin nhắn","contact_form_submitting_button":"Đang gửi...","contact_form_success_message_title":"Tin nhắn đã được gửi!","contact_form_success_message_body":"Cảm ơn bạn đã liên hệ với chúng tôi. Chúng tôi đã nhận được tin nhắn của bạn và sẽ liên hệ lại với bạn trong thời gian sớm nhất.","contact_form_error_name":"Vui lòng nhập tên của bạn.","contact_form_error_email":"Vui lòng nhập địa chỉ email hợp lệ.","contact_form_error_message":"Vui lòng nhập tin nhắn.","contact_prompt":"Nếu bạn cần thêm thông tin hoặc có bất kỳ câu hỏi nào, vui lòng liên hệ với chúng tôi qua email tại <a href=\\"mailto:support@xsave.app\\">support@xsave.app</a>"}');

